#include<cstdio>
#include<vector>
#include<cstring>
#include<algorithm>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int N=1e6+10;int t[N],n,P[N];std::vector<int> V[N];
inline bool cmp(const int &x,const int &y){return V[x].size()>V[y].size();}
inline void Solve()
{
	n=read();rep(1,n,i){V[i].clear();int k=read();while(k--)V[i].push_back(read());}
	rep(1,n,i)P[i]=i;std::sort(P+1,P+n+1,cmp);memset(t,0,sizeof(t));
	rep(1,n,i)if(V[P[i]].size())
	{
		int lst=-1,a=-1,b=-1;bool flag=0;
		for(int v:V[P[i]])if(lst==-1){a=lst=t[v];}
		else if(t[v]!=lst){b=t[v];flag=1;break;}
		if(flag)return printf("YES\n%d %d\n",P[i],a?a:b),void();
		else for(int v: V[P[i]])t[v]=P[i];
	}
	else break; puts("NO"); return;
}
int main(){int T=read();while(T--)Solve();}
